   539→    public static void validateRetentionConfigsWhenRemoteCopyDisabled(Map<?, ?> newConfigs, boolean isRemoteLogStorageEnabled) {
   540→        boolean isRemoteLogCopyDisabled = (Boolean) Utils.castToStringObjectMap(newConfigs).getOrDefault(TopicConfig.REMOTE_LOG_COPY_DISABLE_CONFIG, false);
   541→        long retentionMs = (Long) newConfigs.get(TopicConfig.RETENTION_MS_CONFIG);
   542→        long localRetentionMs = (Long) newConfigs.get(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG);
   543→        long retentionBytes = (Long) newConfigs.get(TopicConfig.RETENTION_BYTES_CONFIG);
   544→        long localRetentionBytes = (Long) newConfigs.get(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG);
   545→        if (isRemoteLogStorageEnabled && isRemoteLogCopyDisabled) {
   546→            if (localRetentionBytes != -2 && localRetentionBytes != retentionBytes) {
   547→                throw new InvalidConfigurationException("When `remote.log.copy.disable` is set to true, the `local.retention.bytes` " +
   548→                        "and `retention.bytes` must be set to the identical value because there will be no more logs copied to the remote storage.");
