   488→    /**
   489→     * Validates the values of the given properties. Should be called only by the broker.
   490→     * The `props` supplied doesn't contain any topic-level configs, only broker-level configs.
   491→     * The default values should be extracted from the KafkaConfig.
   492→     * @param props The properties to be validated
   493→     */
   494→    public static void validateBrokerLogConfigValues(Map<?, ?> props,
   495→                                                     boolean isRemoteLogStorageSystemEnabled) {
   496→        validateValues(props);
   497→        if (isRemoteLogStorageSystemEnabled) {
   498→            validateRemoteStorageRetentionSize(props);
   499→            validateRemoteStorageRetentionTime(props);
   500→        }
   501→    }
   502→
   503→    /**
   504→     * Validates the values of the given properties. Should be called only by the broker.
   505→     * The `newConfigs` supplied contains the topic-level configs,
   506→     * The default values should be extracted from the KafkaConfig.
   507→     * @param existingConfigs                   The existing properties
   508→     * @param newConfigs                        The new properties to be validated
   509→     * @param isRemoteLogStorageSystemEnabled   true if system wise remote log storage is enabled
   510→     */
   511→    private static void validateTopicLogConfigValues(Map<String, String> existingConfigs,
   512→                                                     Map<?, ?> newConfigs,
   513→                                                     boolean isRemoteLogStorageSystemEnabled) {
   514→        validateValues(newConfigs);
   515→
   516→        boolean isRemoteLogStorageEnabled = (Boolean) newConfigs.get(TopicConfig.REMOTE_LOG_STORAGE_ENABLE_CONFIG);
   517→        if (isRemoteLogStorageEnabled) {
   518→            validateRemoteStorageOnlyIfSystemEnabled(newConfigs, isRemoteLogStorageSystemEnabled, false);
   519→            validateRemoteStorageRequiresDeleteCleanupPolicy(newConfigs);
   520→            validateRemoteStorageRetentionSize(newConfigs);
   521→            validateRemoteStorageRetentionTime(newConfigs);
   522→            validateRetentionConfigsWhenRemoteCopyDisabled(newConfigs, isRemoteLogStorageEnabled);
   523→        } else {
   524→            // The new config "remote.storage.enable" is false, validate if it's turning from true to false
   525→            boolean wasRemoteLogEnabled = Boolean.parseBoolean(existingConfigs.getOrDefault(TopicConfig.REMOTE_LOG_STORAGE_ENABLE_CONFIG, "false"));
   526→            validateTurningOffRemoteStorageWithDelete(newConfigs, wasRemoteLogEnabled, isRemoteLogStorageEnabled);
   527→        }
   528→    }
   529→
   530→    public static void validateTurningOffRemoteStorageWithDelete(Map<?, ?> newConfigs, boolean wasRemoteLogEnabled, boolean isRemoteLogStorageEnabled) {
   531→        boolean isRemoteLogDeleteOnDisable = (Boolean) Utils.castToStringObjectMap(newConfigs).getOrDefault(TopicConfig.REMOTE_LOG_DELETE_ON_DISABLE_CONFIG, false);
   532→        if (wasRemoteLogEnabled && !isRemoteLogStorageEnabled && !isRemoteLogDeleteOnDisable) {
   533→            throw new InvalidConfigurationException("It is invalid to disable remote storage without deleting remote data. " +
   534→                    "If you want to keep the remote data and turn to read only, please set `remote.storage.enable=true,remote.log.copy.disable=true`. " +
   535→                    "If you want to disable remote storage and delete all remote data, please set `remote.storage.enable=false,remote.log.delete.on.disable=true`.");
   536→        }
   537→    }
   538→
   539→    public static void validateRetentionConfigsWhenRemoteCopyDisabled(Map<?, ?> newConfigs, boolean isRemoteLogStorageEnabled) {
   540→        boolean isRemoteLogCopyDisabled = (Boolean) Utils.castToStringObjectMap(newConfigs).getOrDefault(TopicConfig.REMOTE_LOG_COPY_DISABLE_CONFIG, false);
   541→        long retentionMs = (Long) newConfigs.get(TopicConfig.RETENTION_MS_CONFIG);
   542→        long localRetentionMs = (Long) newConfigs.get(TopicConfig.LOCAL_LOG_RETENTION_MS_CONFIG);
   543→        long retentionBytes = (Long) newConfigs.get(TopicConfig.RETENTION_BYTES_CONFIG);
   544→        long localRetentionBytes = (Long) newConfigs.get(TopicConfig.LOCAL_LOG_RETENTION_BYTES_CONFIG);
   545→        if (isRemoteLogStorageEnabled && isRemoteLogCopyDisabled) {
   546→            if (localRetentionBytes != -2 && localRetentionBytes != retentionBytes) {
   547→                throw new InvalidConfigurationException("When `remote.log.copy.disable` is set to true, the `local.retention.bytes` " +
   548→                        "and `retention.bytes` must be set to the identical value because there will be no more logs copied to the remote storage.");
   549→            }
   550→            if (localRetentionMs != -2 && localRetentionMs != retentionMs) {
   551→                throw new InvalidConfigurationException("When `remote.log.copy.disable` is set to true, the `local.retention.ms` " +
   552→                        "and `retention.ms` must be set to the identical value because there will be no more logs copied to the remote storage.");
   553→            }
   554→        }
   555→    }
