   569→    @SuppressWarnings("unchecked")
   570→    private static void validateRemoteStorageRequiresDeleteCleanupPolicy(Map<?, ?> props) {
   571→        List<String> cleanupPolicy = (List<String>) props.get(TopicConfig.CLEANUP_POLICY_CONFIG);
   572→        Set<String> policySet = cleanupPolicy.stream().map(policy -> policy.toLowerCase(Locale.getDefault())).collect(Collectors.toSet());
   573→        if (!Set.of(TopicConfig.CLEANUP_POLICY_DELETE).equals(policySet)) {
   574→            throw new ConfigException("Remote log storage only supports topics with cleanup.policy=delete");
   575→        }
   576→    }
