public int deleteOldSegments() throws IOException {
    if (config().delete) {
        return deleteLogStartOffsetBreachedSegments() +
                deleteRetentionSizeBreachedSegments() +
                deleteRetentionMsBreachedSegments();
    } else {
        return deleteLogStartOffsetBreachedSegments();
    }
}

